const dialogues = [
    { "day": 1, "scene": 1, "dialogue": 1, "room": "Parking", "speaker": "Narrateur", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "26 décembre 11h00. Après plusieurs heures de route, la maison apparaît enfin. Le soleil d'hiver se reflète sur la mer au loin.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 2, "room": "Parking", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "text": "Oh on est enfin arrivé ! J'en pouvais plus !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 3, "room": "Parking", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "On peut voir la mer depuis le parking ! C'est super beau !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 4, "room": "Parking", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Je n'aurais jamais imaginé passer les fêtes dans un endroit pareil...", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 5, "room": "Parking", "speaker": "Claude", "sprite": "img/characters/claude.png", "text": "6 heures de route, mais ça en valait le coup", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 6, "room": "Parking", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "text": "Oh, venez m'aider à sortir les bagages", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 7, "room": "Parking", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Tu peux bien le faire tout seul, Subaru !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 8, "room": "Parking", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "text": "Tu as vu le tout ce que vous avez ramené ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 9, "room": "Parking", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "Bon allez, rentrons vite, on se les gèle là....", "visited" : false, "place": "house" },
    { "day": 1, "scene": 1, "dialogue": 10, "room": "Parking", "speaker": "Nina", "sprite": "img/characters/nina.png", "text": "Je sens qu'on va passer un bon séjour ici !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 1, "room": "Hall", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Bon alors, comment est-ce qu'on va se répartir dans les chambres ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 2, "room": "Hall", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "text": "Je me pose dans la grande chambre avec la belle vue sur la mer !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 3, "room": "Hall", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Quoi ? Mais je voulais la prendre !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 4, "room": "Hall", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "text": "Premier arrivé premier servi comme on le dit !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 5, "room": "Hall", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Pfff...", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 6, "room": "Hall", "speaker": "Nina", "sprite": "img/characters/nina.png", "text": "C'est pas grave Erina, on peut s'installer dans la chambre voisine, elle est un poil plus petite, mais on a quand même une très belle vue depuis cette chambre", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 7, "room": "Hall", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Oui, je suppose que c'est quand même bien.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 2, "dialogue": 8, "room": "Hall", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "text": "Bon faisons comme ça : Subaru et Claude dans la chambre 1. Erina et Nina ensemble dans la deuxième chambre. Et Jotaro et moi dans la troisième.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 3, "dialogue": 1, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Bon... Je viens de déposer mes affaires. Je vais voir où en sont les autres.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 4, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Je descends au salon. Pablo est couché sur le canapé. Erina regarde quelque chose près de la fenêtre.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 4, "dialogue": 2, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Hé, Claude ! T'as vu la taille de cet écran ? Ce soir on met un film, c'est obligé.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 4, "dialogue": 3, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Pablo, la dernière fois que t'as choisi le film, on a souffert pendant deux heures.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 4, "dialogue": 4, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "C'était un chef-d'œuvre. T'as juste aucun goût.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 5, "dialogue": 1, "room": "Cuisine", "speaker": "Narrateur", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Je trouve Nina dans la cuisine, elle regarde la mer par la fenêtre.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 5, "dialogue": 2, "room": "Cuisine", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Claude. Tu veux du thé ? J'allais en préparer.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 5, "dialogue": 3, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Volontiers. C'est calme ici, hein.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 5, "dialogue": 4, "room": "Cuisine", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Oui... Ça fait du bien. J'espère qu'on va vraiment pouvoir souffler un peu ce séjour.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 6, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Plus tard dans la soirée, je remonte dans ma chambre. Subaru est déjà là, assis sur son lit, regardant par la fenêtre.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 6, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Subaru ? Ça va ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 6, "dialogue": 3, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Ouais. Je réfléchissais, c'est tout.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 6, "dialogue": 4, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "...", "visited" : false, "place": "house" },
    { "day": 1, "scene": 6, "dialogue": 5, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Allez, c'est bon. Descends, j'arrive dans deux secondes.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 1, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Je suis parti en vacances sur une île récemment. J'ai pris plein de photos, je vais vous montrer ça !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 2, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Oh c'est super beau !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 3, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "text": "Oh qu'est-ce que c'est que ça ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 4, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "C'était le soir où Haruna est décédée. J'étais pas très loin dans un café. Le café était délicieux ! Et l'ambiance sympa. Je voulais immortaliser ce moment, mais maintenan, en y repensant, je n'ai plus un très bon souvenir de ce jour là...", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 5, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "text": "C'est normal.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 6, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "text": "Oh mais on dirait Subaru sur la photo là ? Et Erina !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 7, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Ah oui, on s'est retrouvé là bas ce soir-là. C'était rien de spécial.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 8, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "text": "On s'était croisé par hasard et on a pris un café.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 9, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "Mmmhh... En y repensant, j'avais d'ailleurs cru voir la voiture d'Haruna dans le parking en arrivant.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 10, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "text": "[La voiture d'Haruna... Au café... Ce soir-là ? Personne n'en avait jamais parlé...]", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 11, "room": "Salon", "speaker": "Narrateur", "text": "...", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 12, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "text": "Bon arrêtons de parler de ça. On est là pour passer de bonnes vacances, pas vrai ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 13, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "T'as raison. J'ai encore plein de photos à vous montrer ! Regardez moi ce feu d'artifice !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 7, "dialogue": 14, "room": "Salon", "speaker": "Narrateur", "text": "Pablo regarde fixement Subaru. Nina ne dit rien. Ses yeux se posent quelques instants sur l'appareil photo de Jotaro avant de détourner le regard.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 1, "room": "Chambre 3", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre3.jpg", "music": "calme.mp3", "text": "Jotaro. Tu dors ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 2, "room": "Chambre 3", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "Nina ! Tu m'as fait super peur... Je triais mes photos. Quelque chose ne va pas ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 3, "room": "Chambre 3", "speaker": "Nina", "sprite": "img/characters/nina.png", "text": "Cette photo... Subaru et Erina dans le café, c'était bien la nuit de l'accident d'Haruna ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 4, "room": "Chambre 3", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "Oui, pourquoi ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 5, "room": "Chambre 3", "speaker": "Nina", "sprite": "img/characters/nina.png", "text": "Et tu es sûr que c'était la voiture d'Haruna dans le parking ?", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 6, "room": "Chambre 3", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "Oui absolument ! Elle avait un autocollant d'anime sur la vitre arrière. Impossible de se tromper !", "visited" : false, "place": "house" },
    { "day": 1, "scene": 8, "dialogue": 7, "room": "Chambre 3", "speaker": "Nina", "sprite": "img/characters/nina.png", "text": "D'accord, merci.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 9, "dialogue": 1, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Nuit du 26 décembre. Le premier jour s'achève. Dehors, la mer est noire et silencieuse.", "visited" : false, "place": "house" },
    { "day": 1, "scene": 9, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "text": "Je fixe le plafond. Quelque chose dans cette journée me laisse un drôle de sentiment. Quelque chose que je n'arrive pas encore à savoir quoi...", "visited" : false, "place": "house" },
    { "day": 1, "scene": 9, "dialogue": 3, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "text": "Fin de la journée 1.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 1, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "27 décembre, 9h15. Une lumière grise passe à travers les volets. Le lit d'en face est vide. Subaru est déjà levé.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 1, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Je m'étire. Hier soir, les photos de Jotaro m'ont laissé un drôle d'arrière-goût.]", "visited" : false, "place": "house" },
    { "day": 2, "scene": 2, "dialogue": 3, "room": "Couloir", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Allez ! Tout le monde debout ! On va en ville aujourd'hui !", "visited" : false, "place": "house" },
    { "day": 2, "scene": 2, "dialogue": 4, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Pablo... Il est 9h du matin. On est en vacances.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 2, "dialogue": 5, "room": "Couloir", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Justement ! Les vacances, ça se vit ! Et on a des cadeaux Secret Santa à acheter, alors on s'active !", "visited" : false, "place": "house" },
    { "day": 2, "scene": 2, "dialogue": 6, "room": "Couloir", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Techniquement, Noël est déjà passé, donc on a encore le temps", "visited" : false, "place": "house" },
    { "day": 2, "scene": 2, "dialogue": 7, "room": "Couloir", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Jotaro. Lève-toi.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 1, "room": "Entrée maison", "speaker": "Narrateur", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "Une heure plus tard. Tout le groupe est rassemblé devant la voiture.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 2, "room": "Entrée maison", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "On fait comment pour les cadeaux ? On reste groupés ou on se sépare ?", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 3, "room": "Entrée maison", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "On se sépare, c'est évident. Sinon ça sert à rien le secret.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 4, "room": "Entrée maison", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "Okay, et on se retrouve à midi quelque part pour manger.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 5, "room": "Entrée maison", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "Mouais. De toute façon on sait tous ce qu'on cherche, non ?", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 6, "room": "Entrée maison", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "Plus ou moins. On verra sur place.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 7, "room": "Entrée maison", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "[Moi, j'ai une petite idée pour mon cadeau. Il faut juste que je trouve quelque chose qui correspond bien à Nina.]", "visited" : false, "place": "house" },
    { "day": 2, "scene": 3, "dialogue": 8, "room": "Entrée maison", "speaker": "Narrateur", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "On monte en voiture. La ville est à une vingtaine de minutes.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 4, "dialogue": 1, "room": "Magasin électronique", "speaker": "Narrateur", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Le magasin d'électronique. Rayons bien garnis, musique de Noël en fond sonore, et beaucoup trop de monde pour un 27 décembre.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 2, "room": "Magasin électronique", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Aaaaah. Je suis dans mon élément.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 3, "room": "Magasin électronique", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Jotaro, on est là pour acheter UN truc, pas pour passer la journée ici.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 4, "room": "Magasin électronique", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Un truc... Oui oui, bien sûr. Mais regardez cet objectif ! Une focale de 85mm à ce prix, c'est du jamais vu", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 5, "room": "Magasin électronique", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Jotaro.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 6, "room": "Magasin électronique", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Rooh... si on ne peux même plus s'amuser...", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 7, "room": "Magasin électronique", "speaker": "Narrateur", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Pablo s'arrête devant le rayon musique. Il parcourt les CD du bout des doigts avec une attention inhabituelle.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 8, "room": "Magasin électronique", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Erina, j'ai une question. Quand on écoute de la musique... t'as un genre préféré ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 9, "room": "Magasin électronique", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Pourquoi tu me demandes ça maintenant ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 10, "room": "Magasin électronique", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Comme ça. Par curiosité.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 11, "room": "Magasin électronique", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "J'aime bien le rock. Les trucs un peu énergiques. Pourquoi ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 12, "room": "Magasin électronique", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Non, rien. Cool.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 13, "room": "Magasin électronique", "speaker": "Narrateur", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Il continue de parcourir les CD. Un sourire discret.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 14, "room": "Magasin électronique", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "[Je cherche toujour mon cadeau Secret Santa... Qu'est-ce qui pourrait convenir ?]", "visited" : false, "place": "town" },
    { "day": 2, "scene": 4, "dialogue": 15, "room": "Magasin électronique", "speaker": "Narrateur", "background": "img/backgrounds/magasin1.jpg", "music": "commercial.mp3", "text": "Chacun repart avec son achat, bien dissimulé dans un sac opaque.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 1, "room": "Magasin de vêtements", "speaker": "Narrateur", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "La boutique de vêtements est juste en face. Erina rentre la première.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 2, "room": "Magasin de vêtements", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Oh, regardez cet écharpe ! Elle est trop belle. Enfin bref. On cherche quoi exactement ici ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 3, "room": "Magasin de vêtements", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Moi j'ai une idée précise. Je cherche quelque chose de chaud pour quelqu'un qui se plaint tout le temps d'avoir froid.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 4, "room": "Magasin de vêtements", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Ah. Plutôt vague comme description.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 5, "room": "Magasin de vêtements", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "C'est le principe du Secret Santa Erina...", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 6, "room": "Magasin de vêtements", "speaker": "Narrateur", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Nina, elle, s'est dirigée directement vers le rayon accessoires. Elle trouve des gants et les regarde longuement. Elle semble hésiter.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 7, "room": "Magasin de vêtements", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Bon... Ceux-là me semble pas mal.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 8, "room": "Magasin de vêtements", "speaker": "Narrateur", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Elle choisit une paire de gants de couleur bleu, et plutôt épais.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 9, "room": "Magasin de vêtements", "speaker": "Vendeur", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Bon choix ! C'est du cuir doublé, très chaud.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 10, "room": "Magasin de vêtements", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Parfait, merci beaucoup.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 11, "room": "Magasin de vêtements", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "[Je regarde autour de moi. Il me reste encore à trouver quelque chose pour mon cadeau...]", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 12, "room": "Magasin de vêtements", "speaker": "Narrateur", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Tout le monde repose ses sacs dans la voiture. Midi approche.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 13, "room": "Magasin de vêtements", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Bien. Déjeuner. J'ai vu un resto pas loin qui avait l'air pas mal. On y va ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 15, "room": "Magasin de vêtements", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "J'ai déjà vérifié les avis. 4,2 étoiles, spécialité de poisson, rapport qualité-prix correct. Je valide.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 16, "room": "Magasin de vêtements", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Jotaro. T'as fait ça quand ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 5, "dialogue": 17, "room": "Magasin de vêtements", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/magasin2.jpg", "music": "joyeux.mp3", "text": "Pendant que vous regardiez les écharpes.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 1, "room": "Restaurant", "speaker": "Narrateur", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Dans le restaurant, le groupe prends plusieurs tables. Je me retrouve seul à une table avec Nina.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 2, "room": "Restaurant", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Claude. Je peux te demander un truc ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 3, "room": "Restaurant", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Bien sûr.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 4, "room": "Restaurant", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Subaru... il t'a déjà parlé d'Haruna ? De ce qui s'est passé cette nuit-là ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 5, "room": "Restaurant", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Non. Pas vraiment. On a appris la nouvelle le lendemain matin comme tout le monde. Pourquoi ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 6, "room": "Restaurant", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Rien. Juste pour savoir.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 7, "room": "Restaurant", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "[Elle ne me regarde pas. Elle fixe un point quelque part devant elle.]", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 8, "room": "Restaurant", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Je pense que je vais lui parler. À Subaru. Pendant le séjour.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 9, "room": "Restaurant", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Lui parler... de quoi ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 10, "room": "Restaurant", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "De ce qu'il sait. De ce qu'il ne dit pas.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 11, "room": "Restaurant", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Eh ! Vous venez ? On rentre ?", "visited" : false, "place": "town" },
    { "day": 2, "scene": 6, "dialogue": 12, "room": "Restaurant", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/restaurant.jpg", "music": "joyeux.mp3", "text": "Oui. On arrive.", "visited" : false, "place": "town" },
    { "day": 2, "scene": 7, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "27 décembre, en soirée. Le groupe rentre à la villa. L'ambiance est détendue. Les cadeaux sont cachés, le Secret Santa est pour demain soir.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 2, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Bonne journée les gens. Demain on se pose, et le soir...", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 3, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "T'as déjà une idée de ce qu'on fait ?", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 4, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Karaoké et pizzas !", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 5, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Je rappelle que mon score au karaoké est imbattable depuis 2021.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 6, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Jotaro. Personne a jamais dit que t'étais bon au karaoké.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 7, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Personne a non plus dit le contraire.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 7, "dialogue": 8, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Bon allez bonne nuit tout le monde.", "visited" : false, "place": "house" },
    { "day": 2, "scene": 8, "dialogue": 9, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Nuit du 27 décembre. Je m'allonge. La journée m'a épuisée, mais a été très sympa.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 1, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "28 décembre, 10h40. La villa est silencieuse. Personne ne semble pressé de se lever. Dehors, le ciel est couvert.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 1, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Subaru dort encore. Ou il fait semblant. Je ne sais pas trop.]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 2, "dialogue": 3, "room": "Cuisine", "speaker": "Narrateur", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Je descends seul. Je prépare du café. La villa est étrangement calme.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 2, "dialogue": 4, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Oh Claude ! Tu tombes bien. J'essayais de faire des œufs brouillés mais... je pense que j'ai raté quelque chose.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 2, "dialogue": 5, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "T'as mis quoi dedans ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 2, "dialogue": 6, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Du beurre, des œufs, un peu de sel... et du fromage râpé, parce que j'ai vu une vidéo qui disait que c'était meilleur comme ça.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 2, "dialogue": 7, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "C'est quoi cette texture.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 2, "dialogue": 8, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "calme.mp3", "text": "Je sais pas. C'est pour ça que j'avais besoin d'aide.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 9, "room": "Terrasse", "speaker": "Narrateur", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Pablo est dehors sur la terrasse, café à la main, les yeux perdus sur la mer. Je m'installe à côté de lui un moment.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 10, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Belle vue quand même.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 11, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Ouais.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 12, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Tu as remarqué que Erina était bizarre depuis hier ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 13, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "[Je marque une pause.] Non pourquoi ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 14, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Je sais pas. Elle a l'air un peu tendue. Pas dans son état normal.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 15, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Elle pense peut-être encore à Haruna.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 16, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Oui, c'est ce que je me suis dit aussi... Moi aussi je pense encore beaucoup à Haruna. [Petit silence] Je ne te l'ai jamais dit, mais je pense que je l'aimais...", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 17, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "[Je ne pensais pas qu'il me dirait ça maintenant]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 3, "dialogue": 18, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Enfin. Ce soir on s'amuse, ça va aller.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 1, "room": "Couloir", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "En début d'après-midi. Je croise Nina dans le couloir. Elle s'arrête net, un doigt sur les lèvres.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 2, "room": "Couloir", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Depuis la chambre d'à côté, on entend des voix. Erina et Subaru.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 3, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "(voix étouffée) Tu devrais pas garder ça pour toi, Subaru. Les gens méritent de savoir.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 4, "room": "Couloir", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "(voix étouffée) Et qu'est-ce que ça changerait, Erina ? Ça va rien ramener. Ça va juste faire du mal.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 5, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "(voix étouffée) Nina mérite de savoir la vérité, elle", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 6, "room": "Couloir", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "(voix étouffée) Non. On en parle plus.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 7, "room": "Couloir", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Silence. Nina reste immobile. Puis elle tourne les talons et repart vers sa chambre, sans un mot.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 4, "dialogue": 8, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "[De quelle vérité parlent-ils ?]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Milieu d'après-midi. La porte de notre chambre s'ouvre. Nina entre. Elle cherche Subaru.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 2, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Subaru. J'ai besoin de te parler.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 3, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Maintenant ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 4, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Oui. En privé.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 5, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Elle me regarde. Je comprends. Je sors.]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 6, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Je referme la porte derrière moi. Les voix sont étouffées mais la tension est palpable.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 7, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Ce soir-là, la nuit de l'accident d'Haruna... tu étais avec Erina dans ce café. Pourquoi tu l'as jamais dit à personne ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 8, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Parce que c'était rien. On s'est croisés par hasard, on a discuté un peu. C'est tout.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 9, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "La voiture d'Haruna était dans le parking ce soir-là. Tu l'as vue ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 10, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "...", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 11, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Subaru. Tu l'as vue ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 12, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Nina, laisse tomber. Ça sert à rien de revenir là-dessus. Haruna est partie. On peut pas changer ça.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 13, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Elle venait me voir ce soir-là. Elle m'avait envoyé un message. Elle n'est jamais arrivée.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 14, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Je sais.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 15, "room": "Chambre 1", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Tu sais. Et tu te tais quand même.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 16, "room": "Chambre 1", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Nina... je te demande juste de laisser tomber.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 5, "dialogue": 17, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Plus rien. Quelques instants plus tard, la porte s'ouvre. Nina ressort. Elle ne me regarde pas.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "19h00. Pablo rentre dans le salon avec l'énergie de quelqu'un qui a attendu ce moment toute la journée.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 2, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Bien ! Ce soir, c'est la grande soirée. Secret Santa d'abord, karaoké ensuite, et j'ai commandé des pizzas pour 20h.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 3, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Bien sûr ! Mais j'ai déjà faim...", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 4, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Tu peux bien attendre un peu Jotaro.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 5, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Ca me va perso.Commençons direct par les cadeaux !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 6, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Exactement ! Allez, tout le monde va chercher son cadeau. On se retrouve ici dans cinq minutes.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 6, "dialogue": 7, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Allons-y !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Tout le monde est réuni, cadeaux en main. L'ambiance est plutôt fun.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 2, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Allez, on y va ! Qui commence ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 3, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Moi ! J'ai un cadeau pour... Claude !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 4, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "[Il me tend un paquet soigneusement emballé.]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 5, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "J'espère que ça te plaira. J'ai hésité longtemps, mais j'ai pensé que c'était assez toi.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 6, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "J'ouvre. C'est un beau carnet relié, avec un stylo assorti.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 7, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Merci Jotaro. C'est parfait.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 8, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Je savais ! Mon instinct de détective est infaillible.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 9, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "À moi ! J'ai quelque chose pour... Jotaro.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 10, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Oh ? Qu'est-ce que c'est ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 11, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Jotaro ouvre le paquet. Un rangement modulable pour appareil photo, avec des compartiments pour chaque objectif.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 12, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Pablo. C'est parfait. T'as fait des recherches pour ça ?!", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 13, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Un peu. T'avais l'air d'en avoir besoin.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 14, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "À moi maintenant ! Pablo, c'est pour toi.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 15, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Oh, je sens que c'est un CD...", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 16, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Arrête de palper comme ça !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 17, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Pablo ouvre. C'est un album d'un groupe qu'il connaît bien. Son visage s'illumine.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 18, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Erina ! Comment t'as su que j'aimais ce groupe ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 19, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "J'écoute des fois, tu sais.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 20, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Mon tour. Erina, c'est pour toi.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 21, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Une écharpe ?! Oh, elle est magnifique. Comment t'as su que j'en voulais une ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 22, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Tu te plains d'avoir froid depuis le début du séjour.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 23, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Je me plains pas tant que ça.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 24, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Si.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 25, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "A mon tour, j'ai un cadeau pour Subaru.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 26, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Subaru ouvre et semble ravi.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 27, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Des gants ! Parfait, j'avais perdu les miens la semaine dernière.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 28, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Ils ont l'air épais, ça va être utile.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 29, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Il les enfile aussitôt, puis les retire et les pose sur la table basse.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 30, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Contente que ça te plaise.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 31, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Et moi, j'ai un cadeau pour Nina !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 32, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Je lui tends mon paquet. Nina l'ouvre doucement.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 33, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Merci, Claude. C'est vraiment gentil.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 34, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "J'espère que ça te plaira.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 7, "dialogue": 35, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Bien ! Secret Santa terminé ! Maintenant... karaoké !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "La soirée bat son plein. L'écran du salon affiche les paroles défilantes, la musique couvre tout. L'ambiance s'est réchauffée.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 2, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Écoutez bien ! C'est ma spécialité !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 3, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Jotaro... tu chantes vraiment faux.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 4, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "C'est de l'expressivité. Pas tout le monde peut comprendre.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 5, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Mon tour ! Celle-là, c'est un classique, tout le monde connaît", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 6, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Pablo NON", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 7, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Subaru attrape les gants posés sur la table. Il les réenfile distraitement en attendant son tour.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 8, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Ils sont vraiment bien, ces gants.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 8, "dialogue": 9, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Il les garde quelques minutes, puis les retire à nouveau pour prendre le micro à son tour.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "20h12. La sonnette retentit.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 2, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Les pizzas ! J'y vais !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 3, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Pablo disparaît vers l'entrée. Le karaoké continue. Erina chante à tue-tête, Jotaro commente la performance.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 4, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Voilà les pizzas ! Quatre margheritas et deux quatre fromages, comme commandé.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 5, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Excellente stratégie. Répartition optimale.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 6, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Enfin ! J'ai faim depuis une heure.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 7, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "Les boîtes s'ouvrent sur la table basse. Chacun se sert. Subaru se lève, attrape une part.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 9, "dialogue": 8, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "joyeux.mp3", "text": "[Je prends ma part. L'ambiance est bonne. Pour la première fois depuis hier, je me dis que peut-être]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Subaru mord dans sa part. Une fois, deux fois. Puis il s'arrête.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 2, "room": "Salon", "speaker": "Subaru", "sprite": "img/characters/subaru.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Je... je me sens pas très...", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 3, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Subaru ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 4, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Il pose la pizza. Ses mains tremblent. Il tousse, une fois, fort. Puis il s'effondre.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 5, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "SUBARU !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 6, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Quoi ? qu'est-ce qui se passe Subaru !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 7, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Il faut appeler les secours ! Tout de suite !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 8, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Le chaos s'installe. Pablo se jette à genoux à côté de Subaru. Jotaro a déjà son téléphone à l'oreille. Erina hurle son prénom.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 9, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Allo ?! Oui, on a besoin d'aide, quelqu'un vient de s'effondrer, il respire à peine !", "visited" : false, "place": "house" },
    { "day": 3, "scene": 10, "dialogue": 10, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Je n'entends plus rien correctement. Juste des voix. Le sol. Les secours tardent.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 11, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Les secours arrivent vingt minutes plus tard. Puis la police. La villa se remplit de voix, de radios, de lumières bleues à travers les vitres.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 11, "dialogue": 2, "room": "Salon", "speaker": "Policier", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Personne ne quitte la pièce. On va avoir besoin de prendre vos déclarations.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 11, "dialogue": 3, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Qu'est-ce qui lui est arrivé ? Une crise cardiaque ?", "visited" : false, "place": "house" },
    { "day": 3, "scene": 11, "dialogue": 4, "room": "Salon", "speaker": "Policier", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "On ne peut pas se prononcer pour l'instant. Restez disponibles.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 11, "dialogue": 5, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "[Elle pleure. Jotaro a posé une main maladroite sur son épaule, sans savoir quoi dire.]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 11, "dialogue": 6, "room": "Salon", "speaker": "Policier", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Vous allez tous passer la nuit ici. Des officiers resteront sur place.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 12, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Nuit du 28 décembre. La chambre est à moi seul maintenant. Le lit d'en face est vide.", "visited" : false, "place": "house" },
    { "day": 3, "scene": 12, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Je fixe le plafond. Ce n'était pas un accident.]", "visited" : false, "place": "house" },
    { "day": 3, "scene": 12, "dialogue": 3, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Demain, je dois comprendre ce qui s'est passé.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 1, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "29 décembre à 8h00. La police est toujours là.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 1, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Le lit de Subaru est vide...", "visited" : false, "place": "house" },
    { "day": 4, "scene": 1, "dialogue": 3, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Quelqu'un toque à la porte. J'ouvre. C'est un officier de police.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 1, "dialogue": 4, "room": "Chambre 1", "speaker": "Policier", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "On retrouvera tout le monde dans une heure.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 1, "dialogue": 5, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "D'accord.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 1, "dialogue": 6, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "La porte se ferme. Je suis seul. Je ne peux pas rester là à rien faire... Je vais faire un tour.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 2, "dialogue": 1, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "calme.mp3", "text": "Les agents sont partout dans la villa. Je peux circuler, mais je dois faire attention.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 101, "dialogue": 1, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "enquete.mp3", "text": "Je n'arrive pas à bien observer. Il y a encore quelques policiers par ici. Mais je vois que les boites à pizza ont été déplacées. Les gants par contre n'ont pas bougé, ils sont toujours dans le sachet transparent sur la table basse.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 101, "dialogue": 2, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "enquete.mp3", "text": "Ce sont les gants que Nina a offert à Subaru hier soir.", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 101, "dialogue": 3, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "enquete.mp3", "text": "Je me penche un peu plus. J'ai l'impression de sentir quelque chose de chimique...", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 101, "dialogue": 4, "room": "Salon", "speaker": "Policier", "background": "img/backgrounds/salon.jpg", "music": "enquete.mp3", "text": "Hé monsieur, ne touchez pas !", "visited" : false, "place": "house" },
    { "day": 4, "scene": 101, "dialogue": 5, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "enquete.mp3", "text": "Désolé.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 1, "room": "Cuisine", "speaker": "Narrateur", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Les boites à pizza sont toujours ouvertes sur le plan de travail.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 2, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "[Subaru. C'est forcément lui. Il avait les gants aux mains juste avant de se servir.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 3, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Claude ? Qu'est-ce que tu fais là ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 4, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Je... je cherchais à boire.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 5, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Ah. Moi aussi. (Il s'arrête.) Tu as l'air bizarre.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 6, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Je dors pas bien.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 7, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Moi non plus. (pause) Claude. Tu penses que c'était vraiment un accident ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 8, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "[Il me regarde. Jotaro fait semblant d'être léger, mais là il est sérieux. Vraiment sérieux.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 9, "room": "Cuisine", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Je sais pas encore.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 102, "dialogue": 10, "room": "Cuisine", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/cuisine.jpg", "music": "enquete.mp3", "text": "Moi non plus. Et ça m'inquiète.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 103, "dialogue": 1, "room": "Chambre 3", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre3.jpg", "music": "enquete.mp3", "text": "La chambre de Jotaro et Pablo. Pablo est dehors pour son audition. L'appareil photo de Jotaro est posé sur le bureau, non scellé.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 103, "dialogue": 2, "room": "Chambre 3", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre3.jpg", "music": "enquete.mp3", "text": "[Jotaro m'a dit hier qu'il avait une photo de Erina et Subaru dans le café, la nuit de l'accident d'Haruna. Et qu'il avait aperçu la voiture d'Haruna dans le parking. Si je retrouve cette photo...]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 103, "dialogue": 3, "room": "Chambre 3", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre3.jpg", "music": "enquete.mp3", "text": "Je fais défiler les photos. Des centaines de clichés. Paysages, portraits, détails architecturaux. Et puis", "visited" : false, "place": "house" },
    { "day": 4, "scene": 103, "dialogue": 4, "room": "Chambre 3", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre3.jpg", "music": "enquete.mp3", "text": "[Là. Erina et Subaru, attablés dans un café. Ils ont l'air d'une conversation sérieuse. Subaru fixe sa tasse. Erina lui parle. La date en bas à droite : 14 décembre, 23h47.]", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 103, "dialogue": 5, "room": "Chambre 3", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre3.jpg", "music": "enquete.mp3", "text": "[Et deux photos avant, floue mais reconnaissable : une voiture garée dans le parking du café. Un autocollant panda sur la vitre arrière. La voiture d'Haruna.]", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 103, "dialogue": 6, "room": "Chambre 3", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre3.jpg", "music": "enquete.mp3", "text": "[Haruna était là. Elle a vu Subaru et Erina ensemble. Et juste après...]", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 104, "dialogue": 1, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "La chambre d'Erina et Nina. Erina est à l'audition. Nina est assise sur son lit, les yeux dans le vague.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 2, "room": "Chambre 2", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Claude.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 3, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Je voulais juste voir comment tu allais.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 4, "room": "Chambre 2", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Pas très bien.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 5, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Un silence. Son téléphone est posé face retournée sur la couverture. Elle le saisit, le glisse sous l'oreiller.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 6, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Tu as bien dormi ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 7, "room": "Chambre 2", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Non. (pause) Toi ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 8, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Non.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 9, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Erina entre dans la chambre. Elle s'arrête en me voyant.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 10, "room": "Chambre 2", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Claude. T'as besoin de quelque chose ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 11, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Non. Je repasserai.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 12, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Je sors. Mais je m'arrête dans le couloir. La porte n'est pas tout à fait fermée.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 13, "room": "Chambre 2", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "(voix basse) Nina... tu vas bien ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 104, "dialogue": 14, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Silence. Je m'éloigne sans bruit.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 105, "dialogue": 1, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Plus tard. La chambre est vide. Erina et Nina sont à leurs auditions respectives. Le téléphone de Nina est là, sur le lit, cette fois sans être caché.", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 105, "dialogue": 2, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "[Je sais que je devrais pas. Mais je dois savoir.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 105, "dialogue": 3, "room": "Chambre 2", "speaker": "Narrateur", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "Le téléphone n'est pas verrouillé. Je fais défiler les applications. Et là, une conversation SMS, archivée. Avec Haruna. La dernière date du 14 décembre.", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 105, "dialogue": 4, "room": "Chambre 2", "speaker": "Haruna (SMS)", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "J'arrive. Il faut qu'on parle. De moi, de toi, de tout. J'aurais dû dire ça depuis longtemps.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 105, "dialogue": 5, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "[Haruna venait voir Nina ce soir-là. Pas pour une raison anodine. Pour lui dire quelque chose d'important. Nina l'attendait. Haruna n'est jamais arrivée.]", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 105, "dialogue": 6, "room": "Chambre 2", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre2.jpg", "music": "enquete.mp3", "text": "[Je repose le téléphone exactement comme je l'ai trouvé. Mes mains tremblent légèrement.]", "visited" : false, "place": "house", "indice": true },
    { "day": 4, "scene": 106, "dialogue": 1, "room": "Terrasse", "speaker": "Narrateur", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "Pablo est dehors, proche de la rambarde. Il regarde la mer sans vraiment la voir.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 2, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "Je comprends pas ce qui s'est passé. On était juste là. On mangeait des pizzas et on chantait comme des idiots et puis... voilà.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 3, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "Je sais.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 4, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "La police a l'air de penser que c'est pas un accident. Ils ont dit... ils ont dit qu'ils attendaient des résultats toxicologiques.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 5, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "[Pablo pose la question avec ses yeux sans oser la formuler.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 6, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "T'as remarqué quelque chose, toi ? Pendant la soirée ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 7, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "Je sais pas encore.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 8, "room": "Terrasse", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "Claude. Si t'as vu quelque chose... faut le dire. À la police. À moi. N'importe. Subaru mérite qu'on sache.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 106, "dialogue": 9, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "enquete.mp3", "text": "[Il a raison. Mais je veux d'abord être sûr de ce que j'ai trouvé.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 1, "room": "Couloir", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Erina sort de son audition. Elle a les yeux rouges. Elle s'arrête en me croisant.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 2, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Claude. Il faut qu'on parle.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 3, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "D'accord.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 4, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Subaru et moi, dans le café ce soir-là... Je sais que ça a l'air louche. Mais c'est pas ce que tu crois. On s'est croisés par hasard. Il était dans un sale état.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 5, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Pourquoi ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 6, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "[Elle hésite. Longtemps.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 7, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Subaru et Haruna... ils s'étaient séparés ce soir-là. Quelques heures avant l'accident. C'est Haruna qui avait rompu. Elle aimait Nina...", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 8, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Quoi ?", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 9, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Subaru m'a tout raconté. Il était effondré. On a parlé toute la nuit. Le lendemain matin, on a appris pour Haruna. Il a jamais dit à personne qu'ils s'étaient séparés parce que... parce que ça n'avait plus aucun sens après.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 10, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "[Haruna avait quitté Subaru. Et si elle allait voir Nina ce soir-là... c'est parce qu'elle l'aimait.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 11, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Nina sait pas tout ça. Elle croit encore que... je sais pas exactement ce qu'elle croit. Mais Subaru refusait qu'on lui dise. Il pensait que ça lui ferait trop de mal.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 12, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "[Et Nina a interprété le silence de Subaru comme une culpabilité. Elle a cru qu'il était responsable de la mort d'Haruna.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 13, "room": "Couloir", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "[Elle commence à pleurer] Je ne sais pas quoi faire.", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 14, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "[Je cherche mes mots.]", "visited" : false, "place": "house" },
    { "day": 4, "scene": 107, "dialogue": 15, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "enquete.mp3", "text": "Je sais pas non plus.", "visited" : false, "place": "house" },
    { "day": 5, "scene": 1, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "En fin d'après-midi. Je m'enferme dans ma chambre. Je pose tout à plat.", "visited" : false, "place": "house" },
    { "day": 5, "scene": 1, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Les gants. L'odeur chimique. Les traces sur la boîte. La photo datée. La voiture d'Haruna. Le SMS. La recherche sur le poison. Et ce qu'Erina vient de me dire sur la rupture.]", "visited" : false, "place": "house" },
    { "day": 5, "scene": 1, "dialogue": 3, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Nina croyait que Subaru avait poussé Haruna hors de sa vie et que ça avait causé sa mort. Mais la vérité c'est qu'Haruna avait choisi de partir. Pour aller vers Nina.]", "visited" : false, "place": "house" },
    { "day": 5, "scene": 1, "dialogue": 5, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Demain, la police réunit tout le monde. Je dois décider ce que je fais avec tout ça.]", "visited" : false, "place": "house" },
    { "day": 5, "scene": 2, "dialogue": 1, "room": "Chambre 1", "speaker": "Narrateur", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "Nuit du 29 décembre. La villa est silencieuse.", "visited" : false, "place": "house" },
    { "day": 5, "scene": 2, "dialogue": 2, "room": "Chambre 1", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/chambre1.jpg", "music": "calme.mp3", "text": "[Demain matin. Tout le monde réuni. La vérité ou le silence. Mon choix.]", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "30 décembre, 9h00. L'inspecteur nous réunit tous dans le salon. Cinq chaises, cinq visages. La lumière du matin est froide.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 2, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Merci d'être présents. Les résultats toxicologiques sont arrivés cette nuit. La mort de Subaru est un homicide. Il a été empoisonné.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 3, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Empoisonné...", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 4, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Comment c'est possible ? On était tous là. On mangeait tous la même chose.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 5, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Le poison n'était pas dans la nourriture. Il était sur ses mains. Déposé sur un objet qu'il a manipulé ce soir-là.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 6, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "[Les gants. Il vient de confirmer ce que j'avais compris hier.]", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 7, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Nous avons des raisons de croire que le poison se trouvait sur les gants offerts lors de votre échange de cadeaux. Quelqu'un dans cette pièce les a préparés.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 8, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Quoi ? Mais qui... ?", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 9, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "[Il ne dit rien. Il regarde autour de lui avec une lenteur inhabituellement calculée.]", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 10, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Si quelqu'un ici a des informations à partager, c'est le moment.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 11, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "Silence. Tous les regards convergent vers le centre de la pièce. Puis, progressivement, vers moi.", "visited" : false, "place": "house" },
    { "day": 6, "scene": 1, "dialogue": 12, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "calme.mp3", "text": "[C'est maintenant. Qu'est-ce que je fais de ce que je sais ?]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "FIN A : L'ACCUSATION (accessible si tous les indices trouvés 9)", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 2, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "J'ai des informations.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 3, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Je vous écoute.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 4, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Les gants. Nina, tu les as achetés avant-hier en ville... et tu as hésité longtemps devant le rayon...", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 5, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Claude, tu...", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 6, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Il y a aussi le SMS d'Haruna, conservé dans ton téléphone. Haruna t'a écrit le soir de l'accident... Et puis, les photos de l'appareil de Jotaro qui montrent Subaru et Erina dans le café ce même soir. Nina, tu as vu ces photos n'est-ce pas... Qu'as-tu pensé ?", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 7, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "(se tournant vers Nina) Mademoiselle.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 8, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Long silence. Elle ne pleure pas. Elle regarde ses mains posées sur ses genoux.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 9, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "C'est moi.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 10, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Nina", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 11, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "J'ai mis quelque chose sur les gants. Une substance que j'avais trouvée. Je pensais que Subaru était responsable de la mort d'Haruna. Qu'il l'avait repoussée ce soir-là. Qu'elle s'était précipitée et que c'était à cause de lui.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 12, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Elle venait me voir. Elle m'avait envoyé un message. Elle n'est jamais arrivée. Et lui... il savait. Et il se taisait.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 13, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "(voix brisée) Nina. Il se taisait parce que je lui avais demandé de se taire. Parce que je pensais que tu devais pas savoir.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 14, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Quoi ?", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 15, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Subaru et Haruna s'étaient séparés le soir de l'accident. C'est Haruna qui était partie. Pas lui. Il était effondré dans ce café quand je l'ai croisé. Il pleurait.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 16, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Non.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 17, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Si, Nina. Haruna t'aimait. C'est pour ça qu'elle venait chez toi ce soir-là. Subaru n'a rien fait. Il portait juste la rupture tout seul depuis un an.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 18, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Nina ne dit plus rien. Le silence qui suit est d'une autre nature que tous les autres. Quelque chose vient de se briser, pas seulement dans la pièce, mais en elle.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 19, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "(murmure) J'ai tué quelqu'un pour rien...", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 20, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "L'inspecteur s'approche doucement. Les menottes font un bruit mat. Personne ne bouge.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 21, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Il détourne les yeux. Jotaro fixe le sol. Erina a les mains sur le visage.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 1, "dialogue": 22, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Je la regarde partir. Je ne sais pas si j'ai fait ce qu'il fallait. Je sais seulement que c'est ce qui s'est passé.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "FIN B : LA VÉRITÉ (accessible si indices suffisants mais incomplets 5-7)", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 2, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Les gants. Subaru les a portés deux fois pendant la soirée, juste avant de prendre sa part de pizza. Si le poison était dessus", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 3, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Attends. Les gants, c'est Nina qui les a offerts. Elle les avait choisis elle-même en ville.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 4, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Hé, doucement. On accuse pas les gens comme ça", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 5, "room": "Salon", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Je n'accuse pas. Je suis les faits. Nina avait le mobile, elle était proche d'Haruna. Et Subaru savait quelque chose qu'il ne disait pas. On l'a tous senti.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 6, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "(vers Nina) Mademoiselle. Qu'est-ce que vous avez à dire ?", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 7, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Elle regarde tour à tour chaque visage. Puis elle baisse les yeux.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 8, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "C'est moi.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 9, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Nina, non", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 10, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Je croyais que Subaru était responsable de la mort d'Haruna. Qu'il l'avait repoussée. Qu'elle s'était précipitée dehors ce soir-là à cause de lui. Et il se taisait. Il continuait de se taire.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 11, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "(elle se lève, voix tremblante) Nina. Écoute-moi. Subaru et Haruna avaient rompu ce soir-là. C'est Haruna qui était partie. Il était dans ce café parce qu'il était seul et effondré. Je lui avais demandé de garder ça pour lui. Je pensais que t'aurais pas pu supporter de savoir.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 12, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Pourquoi elle venait chez moi alors ?", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 13, "room": "Salon", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Parce qu'elle t'aimait. Elle voulait te le dire. C'est ça qu'elle voulait te dire.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 14, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Le mot reste en suspens. Le visage de Nina se décompose lentement. Pas de larmes. Quelque chose de pire.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 15, "room": "Salon", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "J'ai tué quelqu'un qui n'avait rien fait...", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 16, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "L'inspecteur intervient. Les événements qui suivent se déroulent dans un silence que personne ne cherche à rompre.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 2, "dialogue": 17, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[J'aurais voulu avoir plus de certitudes. Mais peut-être que dans cette histoire, les certitudes n'auraient rien changé.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "FIN C : LE MAUVAIS COUPABLE (accessible si indices insuffisants -5)", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 2, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Je n'ai pas assez. Pas assez pour accuser quelqu'un. Je me tais.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 3, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Personne n'a rien à ajouter ?", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 4, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Silence. L'inspecteur referme son carnet. Et puis il se tourne vers Pablo.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 5, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Monsieur Pablo. Cette villa appartient à votre famille. Vous êtes le seul à connaître les lieux en détail. Et vous avez commandé les pizzas... vous vous êtes retrouvé seul à la porte quelques minutes ce soir-là.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 6, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Quoi ? C'est... vous plaisantez ? J'allais juste chercher les pizzas.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 7, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Vous avez eu accès aux gants avant la soirée. Et vous aviez un lien particulier avec la victime.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 8, "room": "Salon", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "C'était mon ami ! On était tous amis ! Quelqu'un dites quelque chose", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 9, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Pablo est emmené pour une garde à vue. La pièce se vide progressivement.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 10, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "tension.mp3", "text": "Dans le couloir, je croise Nina. Elle a son manteau. Un sac à la main.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 11, "room": "Couloir", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/couloir.jpg", "music": "tension.mp3", "text": "Claude.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 12, "room": "Couloir", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/couloir.jpg", "music": "tension.mp3", "text": "Nina.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 13, "room": "Couloir", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/couloir.jpg", "music": "tension.mp3", "text": "Je suis désolée.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 3, "dialogue": 14, "room": "Couloir", "speaker": "Narrateur", "background": "img/backgrounds/couloir.jpg", "music": "tension.mp3", "text": "Elle sort. La porte de la villa se referme derrière elle. Je n'essaie pas de la retenir.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 1, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "FIN A bis : LE SILENCE CHOIX (si toutes les preuves + choix de protéger Nina 9)", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 2, "room": "Salon", "speaker": "Inspecteur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Si quelqu'un ici a des informations à partager, c'est le moment.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 3, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Je sais tout. Les gants. Le téléphone. La recherche sur le poison. Le SMS d'Haruna. Je sais pourquoi elle l'a fait. Et je sais que ça ne change rien à ce qu'elle a fait.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 4, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "[Je pense à Haruna. À ce message qu'elle n'a jamais pu délivrer. À Nina qui attendait sans savoir. À Subaru qui portait seul une vérité qu'on lui avait demandé de garder.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 5, "room": "Salon", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "Non. Je n'ai rien à ajouter.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 6, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "L'inspecteur me regarde une seconde de trop. Puis il hoche la tête.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 7, "room": "Salon", "speaker": "Narrateur", "background": "img/backgrounds/salon.jpg", "music": "tension.mp3", "text": "La réunion se termine sans conclusion.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 8, "room": "Terrasse", "speaker": "Narrateur", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Je trouve Nina sur la terrasse. Elle regarde la mer. Je m'installe à côté d'elle sans rien dire.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 9, "room": "Terrasse", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Tu sais.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 10, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Oui.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 11, "room": "Terrasse", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Pourquoi tu n'as rien dit ?", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 12, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "[Je réfléchis. Vraiment.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 13, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Parce qu'Haruna t'aimait. Et parce que personne ne t'a dit la vérité à temps.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 14, "room": "Terrasse", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "[Un long silence. Le vent sur la mer.]", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 15, "room": "Terrasse", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Subaru et Haruna s'étaient séparés ce soir-là. Erina me l'a dit ce matin. C'est Haruna qui était partie.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 16, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Je sais.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 17, "room": "Terrasse", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "J'ai fait quelque chose d'irréparable pour une raison qui n'existait pas.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 18, "room": "Terrasse", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "...", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 19, "room": "Terrasse", "speaker": "Nina", "sprite": "img/characters/nina.png", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "Je vais me rendre. De moi-même. Je voulais juste... voir la mer une dernière fois.", "visited" : false, "place": "house" },
    { "day": 7, "scene": 4, "dialogue": 20, "room": "Terrasse", "speaker": "Narrateur", "background": "img/backgrounds/terrasse.jpg", "music": "calme.mp3", "text": "On reste là encore un moment. Le soleil est bas sur l'horizon. Quelque part derrière nous, la villa attend.", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 1, "room": "Parking", "speaker": "Narrateur", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "30 décembre, après-midi. Les valises sont dans le coffre. La villa se vide.", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 2, "room": "Parking", "speaker": "Jotaro", "sprite": "img/characters/jotaro.png", "text": "Je... je sais pas quoi dire. Je sais jamais quoi dire dans ces moments-là.", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 3, "room": "Parking", "speaker": "Pablo", "sprite": "img/characters/pablo.png", "text": "T'as pas besoin de dire quoi que ce soit.", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 4, "room": "Parking", "speaker": "Erina", "sprite": "img/characters/erina.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "[Elle porte son écharpe. Celle que Subaru lui avait offerte la veille. Elle la serre un peu plus fort.]", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 5, "room": "Parking", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "[On monte en voiture. Je regarde la villa une dernière fois par la vitre. Le soleil se reflète sur la mer au loin, exactement comme le premier jour.]", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 6, "room": "Parking", "speaker": "Claude", "sprite": "img/characters/claude.png", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "[On était 6 en arrivant. On est plus que 4. Et quelque chose qu'on ne pourra pas nommer a changé entre nous...]", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 7, "room": "Parking", "speaker": "Narrateur", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "La voiture démarre. La villa disparaît dans le rétroviseur.", "visited" : false, "place": "house" },
    { "day": 8, "scene": 1, "dialogue": 8, "room": "Parking", "speaker": "Narrateur", "background": "img/backgrounds/entree_maison.jpg", "music": "calme.mp3", "text": "FIN.", "visited" : false, "place": "house" }
]

